    @queue.push(QueuedMessage.new(cached_msid, sender_id, receiver_id, reply_msids[receiver_id]?, func))
  end
end

@queue_mutex.synchronize do
  @queue.push(QueuedMessage.new(nil, nil, receiver, receiver_message, func))
end

